        g: '03028500', avg: 1200, histFlow: 1080, mx: 420, my: 70, abbr: 'PA',
        desc: "Pennsylvania's most beloved canoe river outside of the Delaware — 120 miles through the Allegheny National Forest with the Clarion River Gorge delivering Class I–III paddling through a remote hemlock and hardwood canyon. Designated a National Wild & Scenic River in 1996. Outstanding smallmouth bass fishing, multiple primitive campsites, and genuine Allegheny backcountry solitude.",
        desig: 'National Wild & Scenic River (1996) · Allegheny National Forest',
        secs: ['Upper Clarion — Ridgway to Clarion, Class I–II, open valley', 'Middle Clarion (Cooksburg Gorge) — Class II–III, the best 15-mile gorge section', 'Lower Clarion — Class I, widening toward the Allegheny River'],
        history: [
          { era: 'native', entries: [{ yr: 'Pre-contact', title: "Seneca Nation — The Allegheny Highlands Homeland", text: "The Clarion River watershed was Seneca (Haudenosaunee) territory in the Allegheny Highlands. The Seneca called the region part of the 'Endless Mountains.' The river's name derives from the French word for trumpet — early French trappers described the sound of a high waterfall in the gorge.", src: 'Seneca Nation of Indians; Pennsylvania Historical and Museum Commission' }] },
          { era: 'logging', entries: [{ yr: '1820s–1900', title: 'Clarion Log Drives — The Last Great Pennsylvania Drives', text: "The Clarion River was one of Pennsylvania's most active log drive rivers in the 19th century. White pine and hemlock were floated downstream to mills at Oil City and Pittsburgh. The drives employed thousands of men and ended only after the forests were exhausted.", src: 'Forest County Historical Society; Allegheny National Forest Historical Records' }] },
          { era: 'modern', entries: [{ yr: '1996', title: 'Wild & Scenic Designation — Protecting the Allegheny Forest River', text: 'Congress designated the Clarion as Wild & Scenic in 1996, recognizing the Cooksburg Gorge section and the remarkable ecological recovery of the Allegheny National Forest watershed. The river has rebounded from severe oil and gas pollution of the 19th and early 20th centuries.', src: 'USFS Allegheny NF; National Wild & Scenic Rivers (1996)' }] },
        ],
        docs: [{ t: 'Clarion Wild & Scenic River Management Plan', s: 'USFS Allegheny NF', y: 2001, tp: 'Federal', pg: 145 , url: 'https://www.fs.usda.gov/Internet/FSE_DOCUMENTS/stelprdb5108032.pdf'}],
        revs: [],
        outs: [{ n: 'Clarion River Kayak and Canoe', d: 'Clarion River Gorge rentals and shuttles', l: '' }, { n: 'Cook Forest State Park', d: 'Clarion access and camping, old growth forest', l: 'dcnr.pa.gov' }],
