        g: '06201800', avg: 1400, histFlow: 1280, mx: 382, my: 92, abbr: 'MT',
        desc: "Drains the Beartooth Mountains (one of the highest mountain ranges in the U.S.) through the Absaroka-Beartooth Wilderness to Columbus. The upper river through the Beartooth canyon delivers Class III–IV whitewater in a spectacular alpine gorge; the lower river is a blue-ribbon trout stream in classic Paradise Valley-adjacent scenery. World-class fly fishing for brown and rainbow trout.",
        desig: 'Absaroka-Beartooth Wilderness (headwaters) · Montana Blue-Ribbon Trout Stream',
        secs: ['Upper Stillwater — Beartooth canyon, Class III–IV, wilderness', 'Absaroka to Nye — Class II–III, mountain valley transition', 'Nye to Columbus — Class I–II, lower river, blue-ribbon fishing'],
        history: [
          { era: 'native', entries: [{ yr: 'Pre-contact', title: "Crow (Apsáalooke) — 'The Beartooth People'", text: "The Stillwater River watershed lies at the western edge of the Crow Nation's ancestral territory. The Beartooth Mountains were a spiritual landscape for the Apsáalooke, and the Stillwater valley provided abundant elk, deer, and bison hunting.", src: 'Crow Nation; Stillwater County Historical Society' }] },
          { era: 'logging', entries: [{ yr: '1890s–1920', title: 'Stillwater Mine — Palladium and Platinum', text: 'The Stillwater Complex along the upper river is one of the only deposits of palladium and platinum in North America. The Stillwater Mine (opened 1986) remains the only U.S. producer of platinum group metals, operating under strict environmental oversight.', src: 'Stillwater Mine (Sibanye-Stillwater); Montana Bureau of Mines and Geology' }] },
          { era: 'modern', entries: [{ yr: '2024', title: 'Beartooth Highway — Gateway to the Upper Canyon', text: "US-212, the Beartooth Highway (called 'the most beautiful road in America' by Charles Kuralt), provides access to the upper Stillwater watershed. The highway's seasonal closure — typically mid-October to Memorial Day — concentrates paddling season on spring snowmelt.", src: 'Montana DOT; US Forest Service Custer-Gallatin NF' }] },
        ],
        docs: [],
        revs: [],
        outs: [{ n: 'Absaroka Fly Fishing', d: 'Stillwater River guided float fishing', l: '' }, { n: 'Montana Wilderness Outfitters', d: 'Upper Stillwater canyon trips', l: 'montanawildernessoutfitters.com' }],
