        history: [
          { era: 'native', entries: [{ yr: 'Pre-contact', title: 'Cherokee Homeland — The Blue Ridge Frontier', text: "The Chattooga River watershed was Cherokee territory for thousands of years. Forced removal on the Trail of Tears in 1838 devastated Cherokee communities throughout north Georgia.", src: 'Cherokee Nation; Georgia Historical Society' }] },
          { era: 'logging', entries: [{ yr: '1972', title: 'Deliverance — The Film That Changed a River', text: "James Dickey's novel (1970) and the 1972 film Deliverance, filmed on the Chattooga, transformed the river from an obscure Appalachian stream into an international symbol of wild water.", src: 'USFS Chattahoochee NF; Georgia Film Commission' }] },
          { era: 'modern', entries: [{ yr: '1974', title: 'National Wild & Scenic River Designation', text: "Congress designated the Chattooga as a Wild & Scenic River in 1974, partially in response to the visibility generated by Deliverance.", src: 'USFS; National Wild & Scenic Rivers System' }] },
        ],
