        g: '06485500', avg: 1800, histFlow: 1620, mx: 395, my: 135, abbr: 'SD',
        desc: "South Dakota's eastern gem — the Big Sioux flows through Palisades State Park, where Sioux quartzite cliffs rise 50 feet above the river in a dramatic pink-and-red gorge. The quartzite is 1.7 billion years old, among the oldest exposed rock in North America. Excellent urban paddling through Sioux Falls.",
        desig: 'Palisades State Park · Big Sioux Recreation Area',
        secs: ['Palisades State Park — 8 mi, quartzite gorge, Class I–II', 'Sioux Falls to Brandon — 20 mi, urban prairie paddle', 'Brandon to confluence — 60 mi, wide prairie river'],
        history: [
          { era: 'native', entries: [{ yr: 'Pre-contact', title: 'Dakota Sioux Territory — Blood Run', text: "The Big Sioux watershed was Dakota (Eastern Sioux) territory. Blood Run, a massive Oneota village site near the headwaters, was occupied from 1500–1700 AD and is one of the most significant archaeological sites on the northern Plains — a trading center of perhaps 10,000 people.", src: 'Blood Run National Historic Landmark; South Dakota Archaeological Society' }] },
          { era: 'survey', entries: [{ yr: '1862', title: 'Homestead Act and Dakota War', text: "The Homestead Act of 1862 opened the Big Sioux valley to white settlement. The simultaneous Dakota War in Minnesota drove surviving Dakota people westward, forever altering the river corridor's cultural landscape.", src: 'South Dakota State Historical Society' }] },
        ],
        docs: [{ t: 'Big Sioux River Watershed Assessment', s: 'SD DENR', y: 2014, tp: 'Ecology', pg: 155 , url: 'https://danr.sd.gov/Conservation/WatershedProtection/TMDL/docs/TableDocs/tmdl_bigsiouxcentral.pdf'}],
        revs: [],
