        g: '06431500', avg: 120, histFlow: 108, mx: 395, my: 135, abbr: 'SD',
        desc: "A Black Hills jewel cascading through Spearfish Canyon Scenic Byway — one of the most dramatic canyon drives in America. Spearfish Creek drops over limestone ledges through a 1,000-foot-deep canyon lined with spruce, birch, and ponderosa pine. Bridal Veil and Roughlock Falls punctuate the run.",
        desig: 'Spearfish Canyon Scenic Byway · Black Hills National Forest',
        secs: ['Savoy to Spearfish — 12 mi, canyon run, limestone ledges and falls', 'Upper Spearfish — 8 mi, narrow headwater, intimate forest paddle'],
        history: [
          { era: 'native', entries: [{ yr: 'Pre-contact', title: 'Lakota Sacred Black Hills — Paha Sapa', text: "Spearfish Creek flows from the heart of the Black Hills — Paha Sapa — sacred to the Lakota, Cheyenne, and other Plains peoples for centuries. The creek's name derives from the Lakota practice of spearing fish in its clear waters. The 1868 Fort Laramie Treaty guaranteed the Black Hills to the Lakota, a promise broken after Custer's 1874 gold expedition.", src: 'Lakota Treaty Council; South Dakota State Historical Society' }] },
          { era: 'survey', entries: [{ yr: '1876', title: 'Black Hills Gold Rush', text: "The discovery of gold in the Black Hills triggered an illegal rush into Lakota treaty lands. Miners flooded up Spearfish Creek and its tributaries, establishing the town of Spearfish in 1876. The resulting conflict led to the Great Sioux War and the Battle of Little Bighorn.", src: 'South Dakota State Historical Society; NPS' }] },
        ],
        docs: [],
        revs: [],
        needsVerification: ['named-rapid-scout-note'],
