        g: '10322500', avg: 280, histFlow: 250, mx: 130, my: 220, abbr: 'NV',
        desc: "The longest river entirely within Nevada, flowing 290 miles across the Great Basin before vanishing into the Humboldt Sink. The Humboldt was the lifeline of the California and Oregon Trails — tens of thousands of emigrants followed its course westward through the desert.",
        desig: 'Humboldt River Trail · California Trail Interpretive Center',
        secs: ['Elko to Battle Mountain — 100 mi, upper basin', 'Battle Mountain to Lovelock — 120 mi, lower basin to Humboldt Sink'],
        history: [
          { era: 'native', entries: [{ yr: 'Pre-contact', title: "Western Shoshone Homeland — Newe Sogobia", text: "The Humboldt River corridor was central Western Shoshone (Newe) territory for thousands of years. The river sustained communities across the Great Basin desert. Euro-American emigrant traffic along the Humboldt Trail in the 1840s–1860s brought devastating conflict and displacement.", src: 'Western Shoshone National Council; Nevada Historical Society' }] },
          { era: 'logging', entries: [{ yr: '1841–1869', title: "Oregon and California Trails — Emigrant Lifeline", text: "The Humboldt River was the only reliable water source for hundreds of miles across the Great Basin. An estimated 250,000 emigrants followed the river westward between 1841 and 1869. The California Trail Interpretive Center near Elko preserves this history.", src: 'California Trail Interpretive Center (BLM); Oregon-California Trails Association' }] },
        ],
        docs: [{ t: 'Humboldt River Basin Water Resources Assessment', s: 'Nevada Division of Water Resources', y: 2012, tp: 'Hydrology', pg: 180 , url: 'https://ndep.nv.gov/water/rivers-streams-lakes/special-reports/humboldt-basin-studies'}],
