        co: 'Carroll Co.', len: '84 mi', cls: 'I–III', opt: '400–2000',
        g: '01064500', avg: 1800, histFlow: 1620, mx: 845, my: 115, abbr: 'NH',
        desc: "The most popular canoe river in New England. The Saco flows from Crawford Notch through the Mount Washington Valley, offering sandy beaches, warm summer swimming, and gentle Class I–III rapids through the White Mountains. Multi-day camping trips on river sandbars are a New England rite of passage.",
        desig: 'New Hampshire Rivers Management Program · White Mountain National Forest',
        secs: ['Crawford Notch to North Conway — Class II–III, mountain headwaters', 'North Conway to Fryeburg ME — Class I, sandbar camping classic', 'Fryeburg to Hiram ME — Class I, lower river'],
        history: [
          { era: 'native', entries: [{ yr: 'Pre-contact', title: "Pequawket Abenaki — Saco Valley People", text: "The Saco River valley was home to the Pequawket band of the Abenaki. The name 'Saco' derives from an Abenaki word meaning 'flowing out.' The devastating raid on the Pequawket village at Fryeburg in 1725 (Lovewell's War) effectively ended Abenaki presence in the valley.", src: 'NH Historical Society; Fryeburg Historical Society' }] },
          { era: 'modern', entries: [{ yr: '2023', title: "River Stewardship — Saco Watershed Council", text: "The Saco River Corridor Commission has protected the river's recreational character for decades, managing camping impacts and preserving public access on the most heavily used river in New England.", src: 'Saco River Corridor Commission; AMC' }] },
        ],
        docs: [{ t: 'Saco River Corridor Management Plan', s: 'Saco River Corridor Commission', y: 2015, tp: 'Recreation', pg: 95 , url: 'https://www.des.nh.gov/sites/g/files/ehbemt341/files/documents/saco-swift-plan.pdf'}],
        revs: [],
        outs: [{ n: 'Saco Bound', d: 'New England canoe institution since 1969, Center Conway', l: 'sacobound.com' }, { n: 'Canal Bridge Canoes', d: 'Saco River trips from North Conway', l: '' }],
