        g: '01104500', avg: 280, histFlow: 252, mx: 855, my: 195, abbr: 'MA',
        desc: "The defining river of Greater Boston — 80 miles from Echo Lake in Hopkinton through 23 cities and towns to Boston Harbor. The lower 18-mile stretch is one of the most paddled urban rivers in America, lined with Harvard and MIT boathouses and the Charles River Esplanade. From Watertown upstream, the river winds through quiet suburban marsh and forest with surprising solitude.",
        desig: 'Charles River Watershed Heritage · Charles River Conservancy',
        secs: ['Upper Charles — South Natick to Newton, Class I, suburban marshes', 'Middle Charles — Newton to Watertown Dam, Class I, popular flatwater', 'Lower Charles Basin — Watertown to Boston Harbor, Class I, urban core paddling past Harvard, MIT, and the Esplanade'],
        history: [
          { era: 'native', entries: [{ yr: 'Pre-contact', title: 'Massachusett Homeland — Quinobequin', text: "The Massachusett people called the river Quinobequin ('meandering') and inhabited its banks for thousands of years. The lower river marshes provided abundant alewife, shad, and shellfish. The 1616–1619 epidemic devastated Massachusett communities along the river before the arrival of English settlers in 1630.", src: 'Massachusett Tribe at Ponkapoag; Massachusetts Historical Society' }] },
          { era: 'modern', entries: [{ yr: '1995', title: 'The Clean Charles 2005 Initiative', text: "EPA Region 1 launched the Clean Charles 2005 Initiative in 1995 to make the Charles swimmable. Three decades of work transformed the lower river from a graded D in 1995 to a B+ today, one of the most successful urban river cleanups in American history.", src: 'EPA Region 1; Charles River Watershed Association' }] },
        ],
        docs: [{ t: 'Charles River Watershed Action Plan', s: 'Charles River Watershed Association', y: 2020, tp: 'Ecology', pg: 95, url: 'https://www.crwa.org/' }],
